(5, 'Examination Fee', 'Internal examination fee covering printing of exam papers and invigilation.', 1, 5, 1, '2026-04-24 19:03:07', '2026-04-24 19:03:07'),
(6, 'Sports Levy', 'Covers sports equipment, inter-house sports, and physical education materials.', 1, 6, 1, '2026-04-24 19:03:07', '2026-04-24 19:03:07'),
(7, 'ICT Levy', 'Computer lab maintenance, internet access, and digital learning tools.', 0, 7, 1, '2026-04-24 19:03:07', '2026-04-24 19:03:07'),
